// Clean markdown formatting
const cleanedResponse = aiResponse
  .replace(/^```json\s*\n?/gm, '')
  .replace(/\n?```$/gm, '')
  .trim();

// Parse and return
return JSON.parse(cleanedResponse);

function extractJsonFromText(text) {
  // 1. Nếu có block ```json ... ``` thì lấy phần bên trong
  const match = text.match(/```json\s*([\s\S]*?)\s*```/);
  let jsonString = match && match[1] ? match[1] : text;

  // 2. Cleanup cơ bản
  jsonString = jsonString.trim();
  // Xóa dấu phẩy thừa trước } hoặc ]
  jsonString = jsonString.replace(/,\s*([\]}])/g, "$1");
  // Escape newline thật trong chuỗi (tránh lỗi parse)
  // jsonString = jsonString.replace(/,\s*([\]}])/g, "$1");

  // 3. Parse thử nhiều lớp (JSON trong JSON)
  try {
    let parsed = JSON.parse(jsonString);
    // Nếu parse ra string chứa JSON → parse tiếp
    while (typeof parsed === "string") {
      parsed = JSON.parse(parsed);
    }
    return parsed;
  } catch (err) {
    throw new Error("JSON parse error: " + err.message + "\n--- RAW ---\n" + jsonString);
  }
}



const inputText = $input.first().json.output;

return extractJsonFromText(inputText);
